% --- Per-field readers ---

read_field(header, magic, Bytes, Value) :-
    read_bytes(Bytes, 0, 4, Value).

read_field(header, version, Bytes, Value) :-
    read_u32_le(Bytes, 4, Value).

read_field(header, tensor_count, Bytes, Value) :-
