    read_field(header, version, Bytes, V1),
    read_field(header, tensor_count, Bytes, V2),
    read_field(header, metadata_kv_count, Bytes, V3),
    Pairs = [field(magic, V0), field(version, V1),
             field(tensor_count, V2), field(metadata_kv_count, V3)].


% --- Convenience: read header at absolute byte offset ---
%
% read_section_at(+Section, +Bytes, +Offset, -Pairs, -Consumed)
