% SECTION: tensor_data_section
%
% The tensor data section starts at the next 32-byte alignment
% boundary after the end of the tensor_info_section. Its absolute
% start offset is computed by the caller after parsing all tensor
% info records; individual tensor data is accessed by seeking to
% (tensor_data_start + tensor_info_record.offset).
%
% compute_tensor_data_start(+PostTensorInfoOffset, -AlignedOffset)
% ═══════════════════════════════════════════════════════════════════

%% compute_tensor_data_start(+RawOffset, -AlignedOffset)
%%
%% Rounds RawOffset up to the next 32-byte boundary.
%% Per GGUF v3 spec: alignment = 32 bytes (default; overridable via
%% general.alignment metadata key, but 32 is used here as the default).

compute_tensor_data_start(RawOffset, AlignedOffset) :-
    Alignment = 32,
    Rem is RawOffset mod Alignment,
    (Rem =:= 0
     -> AlignedOffset = RawOffset
     ;  AlignedOffset is RawOffset + (Alignment - Rem)
    ).


% ═══════════════════════════════════════════════════════════════════
% CONVENIENCE: parse a full GGUF file header + all metadata KVs
%
% parse_gguf_header_and_metadata(+Bytes, -Header, -KVPairs)
%
% Parses the 24-byte header and all metadata_kv_count KV pairs.
% Returns:
%   Header   = [field(magic,_), field(version,_), field(tensor_count,_),
%               field(metadata_kv_count,_)]
