parse_gguf_header_and_metadata(Bytes, Header, KVPairs) :-
    read_section_at(header, Bytes, 0, Header, 24),
    member(field(metadata_kv_count, KVCount), Header),
    parse_kv_pairs(KVCount, Bytes, 24, KVPairs, _).

parse_kv_pairs(0, _Bytes, Offset, [], Offset) :- !.
parse_kv_pairs(N, Bytes, Offset, [Pairs | Rest], FinalOffset) :-
    N > 0,
    read_section_at(metadata_kv_pair, Bytes, Offset, Pairs, Consumed),
    NextOffset is Offset + Consumed,
    N1 is N - 1,
    parse_kv_pairs(N1, Bytes, NextOffset, Rest, FinalOffset).


